<?php
 namespace League\CommonMark; use League\CommonMark\Block\Element\AbstractBlock; use League\CommonMark\Block\Element\AbstractStringContainerBlock; use League\CommonMark\Block\Element\Document; use League\CommonMark\Block\Element\Paragraph; use League\CommonMark\Block\Element\StringContainerInterface; use League\CommonMark\Event\DocumentParsedEvent; use League\CommonMark\Event\DocumentPreParsedEvent; use League\CommonMark\Input\MarkdownInput; final class DocParser implements DocParserInterface { private $environment; private $inlineParserEngine; private $maxNestingLevel; public function __construct(EnvironmentInterface $environment) { $this->environment = $environment; $this->inlineParserEngine = new InlineParserEngine($environment); $this->maxNestingLevel = $environment->getConfig('max_nesting_level', \PHP_INT_MAX); if (\is_float($this->maxNestingLevel)) { if ($this->maxNestingLevel === \INF) { @\trigger_error('Using the "INF" constant for the "max_nesting_level" configuration option is deprecated in league/commonmark 1.6 and will not be allowed in 2.0; use "PHP_INT_MAX" instead', \E_USER_DEPRECATED); } else { @\trigger_error('Using a float for the "max_nesting_level" configuration option is deprecated in league/commonmark 1.6 and will not be allowed in 2.0', \E_USER_DEPRECATED); } } } public function parse(string $input): Document { $document = new Document(); $preParsedEvent = new DocumentPreParsedEvent($document, new MarkdownInput($input)); $this->environment->dispatch($preParsedEvent); $markdown = $preParsedEvent->getMarkdown(); $context = new Context($document, $this->environment); foreach ($markdown->getLines() as $line) { $context->setNextLine($line); $this->incorporateLine($context); } $lineCount = $markdown->getLineCount(); while ($tip = $context->getTip()) { $tip->finalize($context, $lineCount); } $this->processInlines($context); $this->environment->dispatch(new DocumentParsedEvent($document)); return $document; } private function incorporateLine(ContextInterface $context): void { $context->getBlockCloser()->resetTip(); $context->setBlocksParsed(false); $cursor = new Cursor($context->getLine()); $this->resetContainer($context, $cursor); $context->getBlockCloser()->setLastMatchedContainer($context->getContainer()); $this->parseBlocks($context, $cursor); if ($this->handleLazyParagraphContinuation($context, $cursor)) { return; } $context->getBlockCloser()->closeUnmatchedBlocks(); $this->setAndPropagateLastLineBlank($context, $cursor); if ($context->getContainer() instanceof StringContainerInterface) { $context->getContainer()->handleRemainingContents($context, $cursor); } elseif (!$cursor->isBlank()) { $p = new Paragraph(); $context->addBlock($p); $cursor->advanceToNextNonSpaceOrTab(); $p->addLine($cursor->getRemainder()); } } private function processInlines(ContextInterface $context): void { $walker = $context->getDocument()->walker(); while ($event = $walker->next()) { if (!$event->isEntering()) { continue; } $node = $event->getNode(); if ($node instanceof AbstractStringContainerBlock) { $this->inlineParserEngine->parse($node, $context->getDocument()->getReferenceMap()); } } } private function resetContainer(ContextInterface $context, Cursor $cursor): void { $container = $context->getDocument(); while ($lastChild = $container->lastChild()) { if (!($lastChild instanceof AbstractBlock)) { break; } if (!$lastChild->isOpen()) { break; } $container = $lastChild; if (!$container->matchesNextLine($cursor)) { $container = $container->parent(); break; } } $context->setContainer($container); } private function parseBlocks(ContextInterface $context, Cursor $cursor): void { while (!$context->getContainer()->isCode() && !$context->getBlocksParsed()) { $parsed = false; foreach ($this->environment->getBlockParsers() as $parser) { if ($parser->parse($context, $cursor)) { $parsed = true; break; } } if (!$parsed || $context->getContainer() instanceof StringContainerInterface || (($tip = $context->getTip()) && $tip->getDepth() >= $this->maxNestingLevel)) { $context->setBlocksParsed(true); break; } } } private function handleLazyParagraphContinuation(ContextInterface $context, Cursor $cursor): bool { $tip = $context->getTip(); if ($tip instanceof Paragraph && !$context->getBlockCloser()->areAllClosed() && !$cursor->isBlank() && \count($tip->getStrings()) > 0) { $tip->addLine($cursor->getRemainder()); return true; } return false; } private function setAndPropagateLastLineBlank(ContextInterface $context, Cursor $cursor): void { $container = $context->getContainer(); if ($cursor->isBlank() && $lastChild = $container->lastChild()) { if ($lastChild instanceof AbstractBlock) { $lastChild->setLastLineBlank(true); } } $lastLineBlank = $container->shouldLastLineBeBlank($cursor, $context->getLineNumber()); while ($container instanceof AbstractBlock && $container->endsWithBlankLine() !== $lastLineBlank) { $container->setLastLineBlank($lastLineBlank); $container = $container->parent(); } } } 